const MENU_REJECT_EXACT_V3 = ["양파라멘","닭고기라멘","소고기라멘","돼지고기라멘","감자라멘","당근라멘","무라멘","양파우동","감자우동","소고기짬뽕","닭고기짬뽕","무갈비찜","감자파스타","양파파스타","대파파스타","닭고기파스타"];
const MENU_REJECT_PATTERNS_V3 = [
  /^(양파|감자|당근|무|대파|마늘|소고기|돼지고기|닭고기)(라멘|우동|파스타)$/,
  /^(소고기|닭고기|돼지고기)짬뽕$/,
  /^무갈비찜$/
];
function isRejectedMenuNameV3(name){
  const q=String(name||'').replace(/\s/g,'').trim();
  return MENU_REJECT_EXACT_V3.some(x=>x.replace(/\s/g,'')===q)||MENU_REJECT_PATTERNS_V3.some(rx=>rx.test(q));
}
function menuGroupOfV3(name){
  const n=flowMenuDBName?flowMenuDBName(name):name;
  for(const [gid,g] of Object.entries(MENU_GROUP_DB_V3)){
    if(g.name===n||g.variations.includes(n)) return g;
  }
  return null;
}

function v2NormText(x){return String(x||'').toLowerCase().replace(/[\s·.,()\[\]{}]/g,'').trim();}
const ING_ALIAS_INDEX_V2 = (()=>{
  const idx={};
  Object.values(INGREDIENT_DB_V2).forEach(i=>{
    [i.name,i.id].concat(i.aliases||[]).forEach(a=>{idx[v2NormText(a)]=i.id;});
  });
  return idx;
})();
function ingredientIdOf(name){
  const n=v2NormText(name);
  if(!n)return null;
  if(ING_ALIAS_INDEX_V2[n])return ING_ALIAS_INDEX_V2[n];
  for(const [alias,id] of Object.entries(ING_ALIAS_INDEX_V2)){
    if(alias && (n.includes(alias)||alias.includes(n))) return id;
  }
  return null;
}
function ingredientNameOf(id){return INGREDIENT_DB_V2[id]?.name || id;}
function ingredientObjOf(id){
  const i=INGREDIENT_DB_V2[id] || {id,name:id,category:'other',icon:getIcon(id),defaultAmount:'적당량',aliases:[]};
  const catMap={grain:'면·밥',protein:'단백질',dairy:'단백질',veg:'채소',fruit:'채소',sauce:'양념',spice:'양념',nut:'기타',other:'기타'};
  return {id:i.id,name:i.name,amount:i.defaultAmount||'적당량',icon:i.icon||getIcon(i.name),category:catMap[i.category]||'기타'};
}

function inferRecipeServingsV3(menu){
  const name = String(menu?.name || '');
  const ids = menu?.ingredients || [];
  const styles = menu?.styles || [menu?.style || ''];
  const has = (...words) => words.some(w => name.includes(w));

  // 대용량/나눠먹는 한식류
  if(has('감자탕','갈비탕','삼계탕','백숙','곰탕','설렁탕','육개장','부대찌개','해물탕','매운탕','샤브샤브','전골')) return 4;
  if(has('돼지갈비찜','소갈비찜','갈비찜','찜닭','닭볶음탕','김치찜','수육','보쌈','족발','잡채')) return 4;
  if(has('김치찌개','된장찌개','차돌된장찌개','순두부찌개','청국장찌개','고추장찌개','동태찌개','참치김치찌개','돼지고기김치찌개')) return 3;
  if(has('카레','하이라이스','짜장','마파두부','라따뚜이','라자냐','무사카')) return 3;

  // 볶음/조림/구이 반찬형은 보통 2인분으로 잡는다.
  if(has('제육볶음','돼지불고기','소불고기','오징어볶음','낙지볶음','쭈꾸미볶음','어묵볶음','감자볶음','멸치볶음','두부조림','고등어조림','갈치조림','코다리조림','장조림')) return 2;
  if(has('닭갈비','오리불고기','탕수육','깐풍기','유린기','깐쇼새우','칠리새우','난자완스','동파육')) return 3;

  // 1인분 완성형: 밥/면/샐러드/토스트/덮밥/파스타/라멘/우동 등
  if(has('덮밥','비빔밥','볶음밥','국수','라면','라멘','우동','소바','냉면','쌀국수','파스타','리조또','오믈렛','토스트','샌드위치','포케','샐러드','오트밀','랩','타코','부리토','퀘사디야')) return 1;
  if(styles.some(s => ['헬시','일식'].includes(s)) && ids.some(id => ['spaghetti','ramen','udon','soba','rice_noodle','bread','tortilla','oatmeal'].includes(id))) return 1;

  // 기본값: 국/찌개/공유요리는 2인분 이상인 경우가 많아 2로 둔다.
  return 2;
}

function normalizeRecipeServingsV4(m){
  const name=String(m?.name||'');
  const ids=m?.ingredients||[];
  const amts=m?.ingredientAmounts||{};
  const num=(id)=>{const v=String(amts[id]||''); const n=parseFloat(v); return Number.isFinite(n)?n:0;};
  const explicit=Math.max(1, Number(m?.servings||m?.recipeServings||0));
  const override={
    '치킨아도보':2,'시니강':2,'똠얌꿍':2,'똠카가이':2,'바쿠테':2,'락사':2,'분보후에':2,
    '렌당':4,'하이난치킨라이스':2,'칠리크랩':2,'사테아얌':2,'가도가도':2,
    '버터치킨커리':3,'치킨티카마살라':3,'팔락파니르':3,'차나마살라':3,'비리야니':3,'탄두리치킨':2
  };
  if(override[name]) return override[name];
  const liquidMl=['water','broth','anchovy_broth','chicken_broth','vegetable_broth','beef_stock','coconut_milk'].reduce((sum,id)=>sum+num(id),0);
  const proteinG=['chicken','pork','beef','shrimp','fish','salmon','duck','lamb'].reduce((sum,id)=>sum+num(id),0);
  const multiDish=/찌개|탕|국|전골|수프|스튜|찜|조림|탕|나베|커리|카레|시니강|똠|락사|바쿠테|렌당|아도보/.test(name);
  if(liquidMl>=500 && multiDish) return Math.max(explicit,2);
  if(proteinG>=280 && multiDish) return Math.max(explicit,2);
  return explicit||1;
}

