function fridgeIngredientIdsV2(){
  return [...new Set((S.fridge||[]).map(f=>ingredientIdOf(f.name||f.replaceName||'')).filter(Boolean))];
}
function flowHasIng(ingName,fridgeNames){
  const id=ingredientIdOf(ingName)||ingName;
  return fridgeIngredientIdsV2().includes(id) || (fridgeNames||[]).some(f=>String(f).includes(ingName)||String(ingName).includes(f));
}
function getIngredientsFromDB(menus, people){
  const merged={};
  let allFound=true;
  const fridgeNames=S.fridge.map(f=>(f.name||'').trim());
  const fridgeIds=fridgeIngredientIdsV2();
  for(const menu of menus||[]){
    const name=flowMenuDBName(menu);
    const db=MENU_DB[name];
    if(!db){allFound=false;continue;}
    for(const ingItem of (db.ingredients||[])){
      // id 있으면 V2 방식, 없으면 name 기반 fallback
      const id=ingItem.id||null;
      const ingName=ingItem.name||ingredientNameOf(id)||'';
      if(!ingName) continue;
      const key=id||ingName;
      // STD_ING에서 amount 직접 참조 (ingObj 변환이 실패했을 경우 대비)
      let amount = ingItem.amount;
      if(!amount || amount === '적당량') {
        const stdData = (typeof STD_ING !== 'undefined' && STD_ING[ingName]);
        amount = stdData ? stdData[0] : '100g';
      }
      const icon=ingItem.icon||getIcon(ingName);
      const category=ingItem.category||'기타';
      const inFridge=id?fridgeIds.includes(id):fridgeNames.some(f=>f.includes(ingName)||ingName.includes(f));
      if(!merged[key]){
        merged[key]={name:ingName, id:key, amount, icon, category, inFridge, usedIn:name};
      } else {
        // 같은 재료 여러 메뉴에 쓰일 때 합산
        const ex=parseFloat(merged[key].amount)||0;
        const cur=parseFloat(amount)||0;
        const unit=(merged[key].amount||amount||'').replace(/[0-9.]/g,'').trim()||'g';
        if(ex&&cur) merged[key].amount=Math.round((ex+cur)*people*10)/10+unit;
        else if(cur) merged[key].amount=Math.round(cur*people*10)/10+unit;
        else if(!ex) merged[key].amount=amount||merged[key].amount;
        merged[key].inFridge=merged[key].inFridge||inFridge;
        if(!String(merged[key].usedIn||'').includes(name))
          merged[key].usedIn=(merged[key].usedIn?merged[key].usedIn+', ':'')+name;
      }
    }
  }
  return {list:Object.values(merged), allFound};
}
function flowScoreMenuByFridge(name){
  const db=MENU_DB[name]; if(!db)return -999;
  const have=new Set(fridgeIngredientIdsV2());
  const ids=db.ingredientIds||[];
  const core=ids.filter(id=>['protein','veg','grain','dairy'].includes(INGREDIENT_DB_V2[id]?.category));
  const haveCount=ids.filter(id=>have.has(id)).length;
  const coreHave=core.filter(id=>have.has(id)).length;
  const missing=Math.max(0,ids.length-haveCount);
  const expiryBoost=(S.fridge||[]).reduce((sum,f)=>{
    const id=ingredientIdOf(f.name); const d=getDday(f.addedAt,f.expireDays);
    return sum+(id&&ids.includes(id)&&d<=3?4:0);
  },0);
  return haveCount*4+coreHave*6+expiryBoost-missing*0.7+getSeasonalScore(name)*1.5-Math.random();
}
function flowMealObj(type,name){
  const db=MENU_DB[name];
  return {type,name,mainIngredients:db?(db.ingredientIds||[]).slice(0,4).map(ingredientNameOf):[],cookTime:db?.cookTime||getCookTime(name),nutrition:{protein:'중간',carb:'중간',veggie:'있음'},sides:getSides(name,type)};
}
function resolveMenu(name){
  if(!name)return null;
  if(MENU_DB[name])return name;
  const q=String(name).trim();
  const exact=Object.keys(MENU_DB).find(k=>k.replace(/\s/g,'')===q.replace(/\s/g,''));
  if(exact)return exact;
  const partial=Object.keys(MENU_DB).find(k=>k.includes(q)||q.includes(k));
  if(partial)return partial;
  return null;
}
function flowMenuDBName(name){return resolveMenu(name)||name;}
function findSimilarMenus(selected,exclude=[]){
  const ex=new Set((exclude||[]).map(flowMenuDBName));
  const seed=(selected||[]).map(flowMenuDBName).filter(n=>MENU_DB[n]);
  const wantedStyles=[...new Set(seed.flatMap(n=>MENU_DB[n].styles||[MENU_DB[n].style]))];
  const wantedIds=[...new Set(seed.flatMap(n=>MENU_DB[n].ingredientIds||[]))];
  return Object.keys(MENU_DB).filter(n=>!ex.has(n)).map(n=>{
    const m=MENU_DB[n];
    const styleScore=(m.styles||[m.style]).some(s=>wantedStyles.includes(s))?5:0;
    const ingScore=(m.ingredientIds||[]).filter(id=>wantedIds.includes(id)).length;
    return {n,score:styleScore+ingScore};
  }).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).map(x=>x.n).slice(0,80);
}

(function(){
  const _oldResolveMenu = typeof resolveMenu === 'function' ? resolveMenu : null;
  window.resolveMenu = resolveMenu = function(name){
    if(!name) return null;
    const raw=String(name).trim();
    const q=raw.replace(/\s/g,'');
    if(isRejectedMenuNameV3(raw)) return null;
    if(MENU_DB[raw]) return raw;
    const exact=Object.keys(MENU_DB).find(k=>k.replace(/\s/g,'')===q);
    if(exact) return exact;
    for(const g of Object.values(MENU_GROUP_DB_V3||{})){
      if(g.name.replace(/\s/g,'')===q) return g.variations.find(v=>MENU_DB[v])||null;
      const v=(g.variations||[]).find(x=>x.replace(/\s/g,'')===q);
      if(v&&MENU_DB[v]) return v;
    }
    const partial=Object.keys(MENU_DB).find(k=>{
      const kk=k.replace(/\s/g,'');
      return kk.includes(q)||q.includes(kk);
    });
    if(partial && !isRejectedMenuNameV3(partial)) return partial;
    return _oldResolveMenu ? _oldResolveMenu(name) : null;
  };

  window.findSimilarMenus = findSimilarMenus = function(selected,exclude=[]){
    const ex=new Set((exclude||[]).map(flowMenuDBName));
    const seed=(selected||[]).map(flowMenuDBName).filter(n=>MENU_DB[n]);
    const groups=new Set(seed.map(n=>{
      for(const [gid,g] of Object.entries(MENU_GROUP_DB_V3||{})){
        if((g.variations||[]).includes(n)) return gid;
      }
      return null;
    }).filter(Boolean));
    const wantedStyles=[...new Set(seed.flatMap(n=>MENU_DB[n].styles||[MENU_DB[n].style]))];
    const wantedIds=[...new Set(seed.flatMap(n=>MENU_DB[n].ingredientIds||[]))];
    return Object.keys(MENU_DB)
      .filter(n=>!ex.has(n)&&!isRejectedMenuNameV3(n))
      .map(n=>{
        const m=MENU_DB[n];
        let gid=null;
        for(const [id,g] of Object.entries(MENU_GROUP_DB_V3||{})){ if((g.variations||[]).includes(n)){ gid=id; break; } }
        const groupScore=gid&&groups.has(gid)?7:0;
        const styleScore=(m.styles||[m.style]).some(s=>wantedStyles.includes(s))?5:0;
        const ingScore=(m.ingredientIds||[]).filter(id=>wantedIds.includes(id)).length;
        return {n,score:groupScore+styleScore+ingScore};
      })
      .filter(x=>x.score>0)
      .sort((a,b)=>b.score-a.score)
      .map(x=>x.n)
      .slice(0,80);
  };

  window.DB_V3_AUDIT = {
    ingredients:Object.keys(INGREDIENT_DB_V2||{}).length,
    menus:Object.keys(MENU_DB||{}).length,
    groups:Object.keys(MENU_GROUP_DB_V3||{}).length,
    variations:Object.values(MENU_GROUP_DB_V3||{}).reduce((s,g)=>s+(g.variations||[]).length,0),
    rejected:MENU_REJECT_EXACT_V3
  };
})();

