    if(!s) return [];
    if(!s.schedule || typeof s.schedule !== 'object') s.schedule = {};
    if(!Array.isArray(s.schedule[day])) s.schedule[day] = [];
    s.schedule[day] = s.schedule[day].filter(function(m){ return ['아침','점심','저녁'].indexOf(m) >= 0; });
    return s.schedule[day];
